import React, { useState, useEffect } from 'react';
import JSZip from 'jszip';
import './App.css';

const logoImg = require('./WhatsApp Image 2026-07-20 at 9.49.24 PM.jpeg');

function App() {
  const [curtainOpen, setCurtainOpen] = useState(false);
  const [logoFade, setLogoFade] = useState(false);
  const [activeTab, setActiveTab] = useState('home');
  const [zipImages, setZipImages] = useState([]);
  const [isLoadingZip, setIsLoadingZip] = useState(true);

  // 1. Curtain Animation Timer
  useEffect(() => {
    const timer1 = setTimeout(() => setLogoFade(true), 1500);
    const timer2 = setTimeout(() => setCurtainOpen(true), 2200);

    return () => {
      clearTimeout(timer1);
      clearTimeout(timer2);
    };
  }, []);

  // 2. Automatically load catalog.zip from public/ folder
  useEffect(() => {
    async function loadCatalogZip() {
      try {
        const response = await fetch('/catalog.zip');
        if (!response.ok) throw new Error('ZIP file not found in public/');
        
        const blob = await response.blob();
        const zip = new JSZip();
        const zipContent = await zip.loadAsync(blob);
        const imagePromises = [];

        zipContent.forEach((relativePath, zipEntry) => {
          if (!zipEntry.dir && /\.(png|jpe?g|svg|webp|gif)$/i.test(zipEntry.name)) {
            const promise = zipEntry.async('blob').then((imgBlob) => ({
              name: zipEntry.name,
              url: URL.createObjectURL(imgBlob),
            }));
            imagePromises.push(promise);
          }
        });

        const extractedImages = await Promise.all(imagePromises);
        setZipImages(extractedImages);
      } catch (err) {
        console.log('Place catalog.zip in client/public/ to auto-load ZIP portfolio.', err);
      } finally {
        setIsLoadingZip(false);
      }
    }

    loadCatalogZip();
  }, []);

  return (
    <div className="app-container" style={{ minHeight: '100vh', background: '#0a0a0a', color: '#fff' }}>
      
      {/* CURTAIN OVERLAY */}
      <div className="curtain-container">
        <div className={`curtain-panel left ${curtainOpen ? 'open' : ''}`} />
        <div className={`curtain-panel right ${curtainOpen ? 'open' : ''}`} />
        <div className={`curtain-logo-wrapper ${logoFade ? 'fade-out' : ''}`}>
          <img src={logoImg} alt="Jillu Curtains" style={{ width: '200px', marginBottom: '15px' }} />
          <p style={{ color: '#d4af37', letterSpacing: '2px', fontWeight: 'bold' }}>WINDOW DRESSING SOLUTIONS</p>
        </div>
      </div>

      {/* HEADER NAVBAR */}
      <header className="navbar">
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <img src={logoImg} alt="Logo" style={{ height: '45px' }} />
          <span className="gold-text" style={{ fontSize: '1.3rem', fontWeight: 'bold' }}>JILLU CURTAINS</span>
        </div>
        <ul className="nav-links">
          {['home', 'about', 'services', 'gallery', 'contact'].map((tab) => (
            <li key={tab} className={activeTab === tab ? 'active' : ''} onClick={() => setActiveTab(tab)}>
              {tab.toUpperCase()}
            </li>
          ))}
        </ul>
      </header>

      {/* DYNAMIC PAGE DISPLAY */}
      <main>
        {activeTab === 'home' && <HomePage setActiveTab={setActiveTab} />}
        {activeTab === 'about' && <AboutPage />}
        {activeTab === 'services' && <ServicesPage zipImages={zipImages} isLoading={isLoadingZip} />}
        {activeTab === 'gallery' && <GalleryPage zipImages={zipImages} isLoading={isLoadingZip} />}
        {activeTab === 'contact' && <ContactPage />}
      </main>

      {/* FOOTER */}
      <footer style={{ borderTop: '1px solid #222', padding: '40px 20px', textAlign: 'center', background: '#0d0d0d', marginTop: '60px' }}>
        <img src={logoImg} alt="Jillu Curtains" style={{ width: '110px', marginBottom: '10px' }} />
        <p className="gold-text" style={{ fontSize: '0.9rem', letterSpacing: '1px' }}>JILLU CURTAINS — WINDOW DRESSING SOLUTIONS</p>
        <p style={{ color: '#666', fontSize: '0.8rem', marginTop: '10px' }}>© 2026 Jillu Curtains. All Rights Reserved.</p>
      </footer>
    </div>
  );
}

/* ==========================================================================
   1. HOME PAGE
   ========================================================================== */
const HomePage = ({ setActiveTab }) => (
  <div>
    {/* Section 1: Hero Banner */}
    <section style={{ 
      position: 'relative', 
      height: '80vh', 
      backgroundImage: 'linear-gradient(rgba(0,0,0,0.65), rgba(0,0,0,0.85)), url("https://images.unsplash.com/photo-1513694203232-719a280e022f?auto=format&fit=crop&w=1600&q=80")', 
      backgroundSize: 'cover', 
      backgroundPosition: 'center', 
      display: 'flex', 
      alignItems: 'center', 
      justifyContent: 'center', 
      textAlign: 'center',
      padding: '0 20px'
    }}>
      <div>
        <h1 className="gold-text" style={{ fontSize: '3.5rem', marginBottom: '15px' }}>Drape Your World in Luxury</h1>
        <p style={{ fontSize: '1.3rem', color: '#e0e0e0', maxWidth: '700px', margin: '0 auto 30px' }}>
          Custom bespoke drapery, motorized blinds, and architectural window treatments tailored for modern interior elegance.
        </p>
        <button className="btn-gold" style={{ padding: '14px 35px', fontSize: '1rem' }} onClick={() => setActiveTab('services')}>
          Explore Our Services & Portfolio
        </button>
      </div>
    </section>

    {/* Section 2: Why Choose Us */}
    <section style={{ padding: '80px 20px', maxWidth: '1200px', margin: '0 auto', textAlign: 'center' }}>
      <h2 className="gold-text" style={{ fontSize: '2.2rem', marginBottom: '15px' }}>The Jillu Standard</h2>
      <p style={{ color: '#aaa', maxWidth: '650px', margin: '0 auto 50px' }}>Crafting timeless elegance with unmatched precision and premium fabrics.</p>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '30px' }}>
        <div style={{ background: '#141414', border: '1px solid #222', padding: '30px', borderRadius: '8px' }}>
          <h3 className="gold-text" style={{ marginBottom: '10px' }}>Hand-Tailored Craft</h3>
          <p style={{ color: '#aaa', fontSize: '0.95rem', lineHeight: '1.6' }}>Every drape is individually measured, hand-cut, and stitched by master artisans.</p>
        </div>
        <div style={{ background: '#141414', border: '1px solid #222', padding: '30px', borderRadius: '8px' }}>
          <h3 className="gold-text" style={{ marginBottom: '10px' }}>Motorized Smart Blinds</h3>
          <p style={{ color: '#aaa', fontSize: '0.95rem', lineHeight: '1.6' }}>Seamless automation compatible with Alexa, Google Home, and home automation systems.</p>
        </div>
        <div style={{ background: '#141414', border: '1px solid #222', padding: '30px', borderRadius: '8px' }}>
          <h3 className="gold-text" style={{ marginBottom: '10px' }}>100% Blackout Linings</h3>
          <p style={{ color: '#aaa', fontSize: '0.95rem', lineHeight: '1.6' }}>Thermal and acoustic blackout layers ensuring complete privacy and climate insulation.</p>
        </div>
      </div>
    </section>

    {/* Section 3: Visual Showcase Grid */}
    <section style={{ background: '#0d0d0d', padding: '80px 20px' }}>
      <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
        <h2 className="gold-text" style={{ textAlign: 'center', fontSize: '2.2rem', marginBottom: '40px' }}>Curated Design Inspiration</h2>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '25px' }}>
          <div style={{ borderRadius: '8px', overflow: 'hidden', height: '280px' }}>
            <img src="https://images.unsplash.com/photo-1540518614846-7ede433c5163?auto=format&fit=crop&w=800&q=80" alt="Living Room Drapes" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
          </div>
          <div style={{ borderRadius: '8px', overflow: 'hidden', height: '280px' }}>
            <img src="https://images.unsplash.com/photo-1616046229478-9901c5536a45?auto=format&fit=crop&w=800&q=80" alt="Motorized Blinds" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
          </div>
          <div style={{ borderRadius: '8px', overflow: 'hidden', height: '280px' }}>
            <img src="https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?auto=format&fit=crop&w=800&q=80" alt="Bedroom Sheer Curtains" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
          </div>
        </div>
      </div>
    </section>

    {/* Section 4: Our Step-by-Step Process */}
    <section style={{ padding: '80px 20px', maxWidth: '1200px', margin: '0 auto', textAlign: 'center' }}>
      <h2 className="gold-text" style={{ fontSize: '2.2rem', marginBottom: '40px' }}>Our Seamless Consultation Process</h2>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '20px' }}>
        <div style={{ padding: '20px', background: '#141414', borderRadius: '8px' }}>
          <h1 className="gold-text">01</h1>
          <h4>In-Home Measurement</h4>
          <p style={{ color: '#888', marginTop: '10px', fontSize: '0.9rem' }}>Laser accuracy measurement at your doorstep.</p>
        </div>
        <div style={{ padding: '20px', background: '#141414', borderRadius: '8px' }}>
          <h1 className="gold-text">02</h1>
          <h4>Fabric Selection</h4>
          <p style={{ color: '#888', marginTop: '10px', fontSize: '0.9rem' }}>Pick from hundreds of velvet, sheer, and linen swatches.</p>
        </div>
        <div style={{ padding: '20px', background: '#141414', borderRadius: '8px' }}>
          <h1 className="gold-text">03</h1>
          <h4>Custom Tailoring</h4>
          <p style={{ color: '#888', marginTop: '10px', fontSize: '0.9rem' }}>Stitched to exact window dimensions in our workshop.</p>
        </div>
        <div style={{ padding: '20px', background: '#141414', borderRadius: '8px' }}>
          <h1 className="gold-text">04</h1>
          <h4>Expert Installation</h4>
          <p style={{ color: '#888', marginTop: '10px', fontSize: '0.9rem' }}>Flawless hanging and motorized calibration.</p>
        </div>
      </div>
    </section>

    {/* Section 5: Client Testimonials */}
    <section style={{ background: '#0d0d0d', padding: '80px 20px', textAlign: 'center' }}>
      <div style={{ maxWidth: '900px', margin: '0 auto' }}>
        <h2 className="gold-text" style={{ fontSize: '2.2rem', marginBottom: '30px' }}>What Our Clients Say</h2>
        <blockquote style={{ fontSize: '1.2rem', fontStyle: 'italic', color: '#ccc', lineHeight: '1.8' }}>
          "The motorized velvet drapes installed by Jillu Curtains transformed our living room completely. The gold hardware detail matches our modern decor perfectly!"
        </blockquote>
        <p style={{ color: '#d4af37', marginTop: '20px', fontWeight: 'bold' }}>— Ananya R., Luxury Villa Owner</p>
      </div>
    </section>

    {/* Section 6: CTA Banner */}
    <section style={{ padding: '80px 20px', textAlign: 'center', background: 'linear-gradient(180deg, #0a0a0a 0%, #17150c 100%)' }}>
      <h2 className="gold-text" style={{ fontSize: '2.5rem', marginBottom: '15px' }}>Ready to Elevate Your Windows?</h2>
      <p style={{ color: '#aaa', marginBottom: '30px' }}>Book your personalized home measurement and fabric consultation today.</p>
      <button className="btn-gold" onClick={() => setActiveTab('contact')}>Schedule Consultation</button>
    </section>
  </div>
);

/* ==========================================================================
   2. ABOUT PAGE
   ========================================================================== */
const AboutPage = () => (
  <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '40px 20px' }}>
    <section style={{ textAlign: 'center', marginBottom: '60px' }}>
      <h1 className="gold-text" style={{ fontSize: '2.8rem', marginBottom: '15px' }}>About Jillu Curtains</h1>
      <p style={{ color: '#ccc', maxWidth: '750px', margin: '0 auto', lineHeight: '1.8', fontSize: '1.1rem' }}>
        Founded with a vision for royal elegance, Jillu Curtains provides tailored window dressing solutions for homes, penthouses, and commercial spaces.
      </p>
    </section>

    <section style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '40px', alignItems: 'center', marginBottom: '60px' }}>
      <div>
        <h2 className="gold-text" style={{ marginBottom: '15px' }}>Master Tailoring Tradition</h2>
        <p style={{ color: '#aaa', lineHeight: '1.8' }}>
          Every curtain panel created at Jillu Curtains undergoes a multi-step quality control process. From weighted hems to double-pleated headers, we ensure your drapes hang with perfect architectural symmetry.
        </p>
      </div>
      <img src="https://images.unsplash.com/photo-1513694203232-719a280e022f?auto=format&fit=crop&w=600&q=80" alt="Workmanship" style={{ width: '100%', borderRadius: '8px', border: '1px solid #333' }} />
    </section>

    <section style={{ background: '#141414', padding: '40px', borderRadius: '8px', border: '1px solid #222', marginBottom: '60px' }}>
      <h2 className="gold-text" style={{ textAlign: 'center', marginBottom: '30px' }}>Our Core Pillars</h2>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '20px' }}>
        <div><h4 className="gold-text">Precision</h4><p style={{ color: '#888', fontSize: '0.9rem' }}>Millimeter accuracy in measuring and tailoring.</p></div>
        <div><h4 className="gold-text">Quality</h4><p style={{ color: '#888', fontSize: '0.9rem' }}>Premium blackout, jacquard, and silk fabrics.</p></div>
        <div><h4 className="gold-text">Innovation</h4><p style={{ color: '#888', fontSize: '0.9rem' }}>Smart electric curtain tracks and motorization.</p></div>
      </div>
    </section>

    <section style={{ marginBottom: '60px' }}>
      <h2 className="gold-text" style={{ textAlign: 'center', marginBottom: '30px' }}>Exquisite Materials</h2>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px', textAlign: 'center' }}>
        <div style={{ padding: '20px', background: '#0d0d0d', border: '1px solid #222', borderRadius: '6px' }}><h4 style={{ color: '#fff' }}>Royal Velvet</h4></div>
        <div style={{ padding: '20px', background: '#0d0d0d', border: '1px solid #222', borderRadius: '6px' }}><h4 style={{ color: '#fff' }}>Linen Sheers</h4></div>
        <div style={{ padding: '20px', background: '#0d0d0d', border: '1px solid #222', borderRadius: '6px' }}><h4 style={{ color: '#fff' }}>Jacquard Damask</h4></div>
        <div style={{ padding: '20px', background: '#0d0d0d', border: '1px solid #222', borderRadius: '6px' }}><h4 style={{ color: '#fff' }}>Thermal Silk</h4></div>
      </div>
    </section>

    <section style={{ background: '#141414', padding: '40px', borderRadius: '8px', textAlign: 'center', marginBottom: '60px' }}>
      <h2 className="gold-text" style={{ marginBottom: '15px' }}>Expert Installation Team</h2>
      <p style={{ color: '#aaa', maxWidth: '700px', margin: '0 auto' }}>Our technicians are certified installers for all high-end motorized track systems and ceiling-recessed drapes.</p>
    </section>

    <section style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: '20px', textAlign: 'center' }}>
      <div style={{ padding: '20px', background: '#0d0d0d', border: '1px solid #d4af37', borderRadius: '8px' }}><h1 className="gold-text">500+</h1><p style={{ color: '#aaa' }}>Projects Finished</p></div>
      <div style={{ padding: '20px', background: '#0d0d0d', border: '1px solid #d4af37', borderRadius: '8px' }}><h1 className="gold-text">100%</h1><p style={{ color: '#aaa' }}>Custom Fitted</p></div>
      <div style={{ padding: '20px', background: '#0d0d0d', border: '1px solid #d4af37', borderRadius: '8px' }}><h1 className="gold-text">15+</h1><p style={{ color: '#aaa' }}>Years Experience</p></div>
    </section>
  </div>
);

/* ==========================================================================
   3. SERVICES PAGE
   ========================================================================== */
const ServicesPage = ({ zipImages, isLoading }) => (
  <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '40px 20px' }}>
    <section style={{ textAlign: 'center', marginBottom: '50px' }}>
      <h1 className="gold-text" style={{ fontSize: '2.8rem', marginBottom: '10px' }}>Services & Design Portfolio</h1>
      <p style={{ color: '#aaa', fontSize: '1.1rem' }}>Bespoke tailoring, motorized blinds, and extracted design catalog.</p>
    </section>

    <section style={{ background: '#141414', border: '1px solid #d4af37', padding: '30px', borderRadius: '12px', marginBottom: '60px' }}>
      <h2 className="gold-text" style={{ textAlign: 'center', marginBottom: '10px' }}>Extracted Catalog Portfolio</h2>
      <p style={{ color: '#888', textAlign: 'center', marginBottom: '30px' }}>Loaded directly from <code>client/public/catalog.zip</code> archive</p>

      {isLoading ? (
        <p style={{ color: '#d4af37', textAlign: 'center', fontSize: '1.2rem' }}>Unpacking catalog archive photos...</p>
      ) : zipImages.length > 0 ? (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: '20px' }}>
          {zipImages.map((img, idx) => (
            <div key={idx} style={{ background: '#0a0a0a', border: '1px solid #333', borderRadius: '8px', padding: '10px' }}>
              <img src={img.url} alt={img.name} style={{ width: '100%', height: '200px', objectFit: 'cover', borderRadius: '6px' }} />
              <p style={{ color: '#888', fontSize: '0.8rem', marginTop: '8px', textAlign: 'center', wordBreak: 'break-all' }}>{img.name}</p>
            </div>
          ))}
        </div>
      ) : (
        <div style={{ textAlign: 'center', padding: '20px' }}>
          <p style={{ color: '#ccc' }}>No images extracted yet. Make sure your portfolio archive is saved at <code>client/public/catalog.zip</code>.</p>
        </div>
      )}
    </section>

    <section style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '30px', alignItems: 'center', marginBottom: '50px' }}>
      <img src="https://images.unsplash.com/photo-1540518614846-7ede433c5163?auto=format&fit=crop&w=600&q=80" alt="Tailored Drapes" style={{ width: '100%', borderRadius: '8px' }} />
      <div>
        <h2 className="gold-text">Custom Tailored Drapery</h2>
        <p style={{ color: '#aaa', marginTop: '15px', lineHeight: '1.7' }}>Pinch-pleat, ripple-fold, wave fold, and grommet style drapery crafted to exact floor-to-ceiling dimensions.</p>
      </div>
    </section>

    <section style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '30px', alignItems: 'center', marginBottom: '50px' }}>
      <div>
        <h2 className="gold-text">Motorized & Smart Blinds</h2>
        <p style={{ color: '#aaa', marginTop: '15px', lineHeight: '1.7' }}>Whisper-quiet motorized tracks allowing automatic timer schedules and smartphone app control.</p>
      </div>
      <img src="https://images.unsplash.com/photo-1616046229478-9901c5536a45?auto=format&fit=crop&w=600&q=80" alt="Motorized Blinds" style={{ width: '100%', borderRadius: '8px' }} />
    </section>

    <section style={{ background: '#141414', padding: '40px', borderRadius: '8px', textAlign: 'center', marginBottom: '50px' }}>
      <h2 className="gold-text" style={{ marginBottom: '15px' }}>Commercial Window Treatments</h2>
      <p style={{ color: '#aaa', maxWidth: '750px', margin: '0 auto' }}>Fire-retardant fabrics and motorized blackout blinds for luxury hotels, offices, and restaurant venues.</p>
    </section>

    <section style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '30px', alignItems: 'center', marginBottom: '50px' }}>
      <img src="https://images.unsplash.com/photo-1540518614846-7ede433c5163?auto=format&fit=crop&w=600&q=80" alt="Tailored Drapes" style={{ width: '100%', borderRadius: '8px' }} />
      <div>
        <h2 className="gold-text">Custom Tailored Drapery</h2>
        <p style={{ color: '#aaa', marginTop: '15px', lineHeight: '1.7' }}>Pinch-pleat, ripple-fold, wave fold, and grommet style drapery crafted to exact floor-to-ceiling dimensions.</p>
      </div>
    </section>

    <section style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '30px', alignItems: 'center', marginBottom: '50px' }}>
      <div>
        <h2 className="gold-text">Motorized & Smart Blinds</h2>
        <p style={{ color: '#aaa', marginTop: '15px', lineHeight: '1.7' }}>Whisper-quiet motorized tracks allowing automatic timer schedules and smartphone app control.</p>
      </div>
      <img src="https://images.unsplash.com/photo-1616046229478-9901c5536a45?auto=format&fit=crop&w=600&q=80" alt="Motorized Blinds" style={{ width: '100%', borderRadius: '8px' }} />
    </section>

    <section style={{ background: '#141414', padding: '40px', borderRadius: '8px', textAlign: 'center', marginBottom: '50px' }}>
      <h2 className="gold-text" style={{ marginBottom: '15px' }}>Commercial Window Treatments</h2>
      <p style={{ color: '#aaa', maxWidth: '750px', margin: '0 auto' }}>Fire-retardant fabrics and motorized blackout blinds for luxury hotels, offices, and restaurant venues.</p>
    </section>

    <section style={{ border: '1px solid #d4af37', padding: '30px', borderRadius: '8px', textAlign: 'center' }}>
      <h3 className="gold-text">Our Quality Commitment</h3>
      <p style={{ color: '#888', marginTop: '10px' }}>Every motor and stitch comes with a 5-year Jillu Curtains warranty.</p>
    </section>
  </div>
);

/* ==========================================================================
   4. GALLERY PAGE
   ========================================================================== */
const GalleryPage = ({ zipImages, isLoading }) => (
  <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '40px 20px' }}>
    <section style={{ textAlign: 'center', marginBottom: '40px' }}>
      <h1 className="gold-text" style={{ fontSize: '2.8rem', marginBottom: '10px' }}>Interactive Photo Gallery</h1>
      <p style={{ color: '#aaa' }}>Explore our completed residential and commercial projects.</p>
    </section>

