      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '20px' }}>
        <img src="https://images.unsplash.com/photo-1513694203232-719a280e022f?auto=format&fit=crop&w=600&q=80" alt="Gallery 1" style={{ width: '100%', height: '240px', objectFit: 'cover', borderRadius: '6px' }} />
        <img src="https://images.unsplash.com/photo-1540518614846-7ede433c5163?auto=format&fit=crop&w=600&q=80" alt="Gallery 2" style={{ width: '100%', height: '240px', objectFit: 'cover', borderRadius: '6px' }} />
        <img src="https://images.unsplash.com/photo-1616046229478-9901c5536a45?auto=format&fit=crop&w=600&q=80" alt="Gallery 3" style={{ width: '100%', height: '240px', objectFit: 'cover', borderRadius: '6px' }} />
      </div>
    </section>

    <section style={{ background: '#141414', padding: '30px', borderRadius: '8px', marginBottom: '60px' }}>
      <h3 className="gold-text" style={{ marginBottom: '10px' }}>Velvet & Blackout Styles</h3>
      <p style={{ color: '#aaa' }}>Rich texture combinations designed to insulate acoustics and block ambient sunlight.</p>
    </section>

    <section style={{ background: '#141414', padding: '30px', borderRadius: '8px', marginBottom: '60px' }}>
      <h3 className="gold-text" style={{ marginBottom: '10px' }}>Linen & Sheer Diffusers</h3>
      <p style={{ color: '#aaa' }}>Ethereal daylight diffusion creating warm ambient lighting across living areas.</p>
    </section>

    <section style={{ textAlign: 'center' }}>
      <h3 className="gold-text">Like What You See?</h3>
      <p style={{ color: '#aaa', margin: '10px 0 20px' }}>Request fabric samples sent directly to your residence.</p>
    </section>
  </div>
);

